    if (state.plannerIndex < 0 || listed.indexOf(state.plannerIndex) < 0) {
      state.plannerIndex = listed[0];
      renderPlannerRepList();
      renderPlannerRepEditor();
      return;
    }
    renderPlannerRepEditor();
