    $('importInput').addEventListener('change', function (e) {
      var f = e.target.files && e.target.files[0];
      if (!f) return;
      var r = new FileReader();
      r.onload = async function () {
        try {
          var payload = JSON.parse(String(r.result || '{}'));
          // Handle new payload structure with separate public/internal sections
          var data = {};
          if (payload.public && isObject(payload.public)) {
            Object.keys(payload.public).forEach(function (k) { data[k] = payload.public[k]; });
          }
          if (payload.internal && isObject(payload.internal)) {
            Object.keys(payload.internal).forEach(function (k) { data[k] = payload.internal[k]; });
          }
          // Backward compatibility: handle old payload structure with single data object
          if (payload.data && isObject(payload.data)) {
            Object.keys(payload.data).forEach(function (k) { data[k] = payload.data[k]; });
          }
          // Backward compatibility: handle _legacyData
          if (payload._legacyData && isObject(payload._legacyData)) {
            Object.keys(payload._legacyData).forEach(function (k) { data[k] = payload._legacyData[k]; });
          }
          if (!isObject(data)) throw new Error('The file needs a "data" object with content keys.');
          var scope = getImportScopeValue();
          var keysAll = Object.keys(data).filter(function (k) { return SAFE_IMPORT_KEY_RE.test(k); });
          var keys = filterImportKeys(keysAll, scope);
          var previewLines = [
            'File: ' + safeString(f.name),
            'Import scope: ' + getImportScopeLabel(),
            'Compatible in file: ' + keysAll.length,
            'Will import now: ' + keys.length,
            '',
            'Areas to update:',
            keys.slice(0, 40).map(function (k) { return '• ' + humanStorageKeyLine(k); }).join('\n') + (keys.length > 40 ? '\n• … and ' + (keys.length - 40) + ' more' : '')
          ];
          $('import-preview').value = previewLines.join('\n');
          if (!keysAll.length) throw new Error('No compatible content found in this file.');
          if (!keys.length) {
            throw new Error('Nothing matches the current import scope. Widen scope to "All compatible content" or pick a different file.');
          }
          var warn = [
            'Import will overwrite matching content in the admin.',
            '',
            'Strongly recommended: create a backup first (System / Tools → Create backup now).',
            '',
            'Scope: ' + getImportScopeLabel(),
            'Number of areas to write: ' + keys.length,
            '',
            'Proceed with import?'
          ].join('\n');
          if (!window.confirm(warn)) {
            setStatus('Import cancelled', 'warn');
            pushActivitySummary('Import cancelled', ['No changes were saved.']);
            return;
          }
          for (var i = 0; i < keys.length; i++) {
            var k = keys[i];
            validateKeyValue(k, data[k]);
            if (k === 'rg_admin_contacts_followups') {
              state.contactsDoc = safeContactsDoc(clone(data[k]));
              if (!await saveDocRequired('rg_admin_contacts_followups', state.contactsDoc)) {
                throw new Error('Could not import ' + humanStorageKeyLine(k));
              }
            } else if (k === 'rg_admin_cases') {
              state.casesDoc = safeCasesDoc(clone(data[k]));
              if (!await saveDocRequired('rg_admin_cases', state.casesDoc)) {
                throw new Error('Could not import ' + humanStorageKeyLine(k));
              }
            } else if (k === 'rg_outreach_tracker') {
              state.outreachDoc = safeOutreachDoc(clone(data[k]));
              if (!await saveDocRequired('rg_outreach_tracker', state.outreachDoc)) {
                throw new Error('Could not import ' + humanStorageKeyLine(k));
              }
            } else {
              if (!await saveDocRequired(k, clone(data[k]))) {
                throw new Error('Could not import ' + humanStorageKeyLine(k));
              }
            }
          }
          refreshCurrentSection();
          markDirty(false, 'Import saved');
          setStatus('Import complete', 'ok');
          pushActivitySummary('Import finished', [
            keys.length + ' area(s) updated.',
            'Scope was: ' + getImportScopeLabel() + '.',
            'Reload sections if something looks stale.'
          ]);
        } catch (err) {
          setStatus('Import failed: ' + err.message, 'err');
          alert('Import failed: ' + err.message);
          pushActivitySummary('Import failed', [safeString(err.message)]);
        } finally {
          e.target.value = '';
        }
      };
      r.readAsText(f);
    });
